import{_ as a,o as i,c as s,a2 as o}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"Serviços","description":"","frontmatter":{},"headers":[],"relativePath":"pt/api/services.md","filePath":"pt/api/services.md"}'),r={name:"pt/api/services.md"};function t(c,e,n,d,l,p){return i(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="servicos" tabindex="-1">Serviços <a class="header-anchor" href="#servicos" aria-label="Permalink to &quot;Serviços&quot;">​</a></h1><p>Todos os serviços do Clearance residem em <code>src/Services/</code> e são resolvidos a partir do container, ex. <code>app(ContextService::class)</code>. São a camada a usar a partir de controllers, políticas, e jobs — em qualquer lugar onde o modelo <code>User</code> possa não usar a trait <code>HasClearance</code>.</p><h2 id="contextservice" tabindex="-1"><code>ContextService</code> <a class="header-anchor" href="#contextservice" aria-label="Permalink to &quot;`ContextService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\ContextService</code> (<code>src/Services/ContextService.php</code>) é o motor por trás da autorização contextual. O <a href="/clearance-docs/pt/api/facade.html">facade <code>Clearance</code></a> e a trait <code>HasClearance</code> delegam ambos para ele.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Services\\ContextService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ContextService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">canIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;orders-create&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hasPermissionIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;orders-create&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// alias</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hasRoleIn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;manager&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $store);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolveFor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($user, $store); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Collection of all effective permission names</span></span></code></pre></div><p>O <code>resolveFor()</code> constrói o seu resultado usando uma precedência de 3 fontes:</p><ol><li>Concessões de papel contextuais</li><li>Concessões de papel globais</li><li>Substituições por contexto (<code>forced_on</code> acrescenta, <code>forced_off</code> ganha sempre)</li></ol><p>Ver <a href="/clearance-docs/pt/features/contextual-authorization.html">Autorização Contextual</a> para a explicação conceptual desta precedência.</p><h2 id="roleservice" tabindex="-1"><code>RoleService</code> <a class="header-anchor" href="#roleservice" aria-label="Permalink to &quot;`RoleService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\RoleService</code> (<code>src/Services/RoleService.php</code>) gere papéis-teto.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Rivalex\\Clearance\\Services\\RoleService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">RoleService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setParent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($childRole, $parentRole);</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">RoleService</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">removeParent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($childRole);</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Método</th><th>Descrição</th></tr></thead><tbody><tr><td><code>setParent($childRole, $parentRole)</code></td><td>Define um teto: as permissões em excesso em <code>$childRole</code> além do conjunto do principal são silenciosamente cortadas. Lança <code>ClearanceScopeViolationException</code> se o filho já for um principal, ou o principal já for um filho.</td></tr><tr><td><code>removeParent($childRole)</code></td><td>Remove a relação de teto.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Um teto apenas corta — nunca concede. Um papel principal permissivo não dá, por si só, qualquer permissão ao filho. Remover uma permissão de um papel principal propaga essa remoção automaticamente a todos os papéis filho.</p></div><p>Ver <a href="/clearance-docs/pt/features/roles.html">Papéis</a> para o conceito de papel-teto em maior profundidade.</p><h2 id="permissionservice" tabindex="-1"><code>PermissionService</code> <a class="header-anchor" href="#permissionservice" aria-label="Permalink to &quot;`PermissionService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\PermissionService</code> (<code>src/Services/PermissionService.php</code>) suporta o CRUD do painel de Permissões.</p><p>Aplica a convenção de nomenclatura <code>group-action</code>, controlada pelas chaves de configuração <code>enforce_naming_convention</code> e <code>naming_separator</code>, e protege o namespace de permissões <code>clearance-*</code> de ser criado, renomeado, ou eliminado fora do fluxo de instalação.</p><h2 id="guardservice" tabindex="-1"><code>GuardService</code> <a class="header-anchor" href="#guardservice" aria-label="Permalink to &quot;`GuardService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\GuardService</code> (<code>src/Services/GuardService.php</code>) suporta o CRUD do painel de Guards.</p><p>Injeta guards apoiados em base de dados em <code>auth.guards</code> no arranque, filtrados pela chave de configuração <code>allowed_guard_drivers</code> — um driver não listado é ignorado com um aviso no log em vez de corromper a configuração de autenticação.</p><h2 id="metaservice" tabindex="-1"><code>MetaService</code> <a class="header-anchor" href="#metaservice" aria-label="Permalink to &quot;`MetaService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\MetaService</code> (<code>src/Services/MetaService.php</code>) lê e escreve <code>clr_meta</code> (nome de exibição, descrição, ícone SVG sanitizado, cor) para um papel ou guard sujeito. Suporta o editor de metadados de exibição do painel de Configurações.</p><p>Os ícones SVG passam por <code>Rivalex\\Clearance\\Support\\SvgSanitizer</code> (um sanitizador com lista de permissões) tanto antes do armazenamento como no momento da renderização.</p><h2 id="userclearanceservice" tabindex="-1"><code>UserClearanceService</code> <a class="header-anchor" href="#userclearanceservice" aria-label="Permalink to &quot;`UserClearanceService`&quot;">​</a></h2><p><code>Rivalex\\Clearance\\Services\\UserClearanceService</code> (<code>src/Services/UserClearanceService.php</code>) suporta o painel do módulo de Utilizadores:</p><ul><li>Atribuição de papel global</li><li>Atribuição de papel contextual (via <code>UserRoleContext</code>)</li><li>Substituições de permissão por contexto (via <code>UserContextPermissionOverride</code>, <code>forced_on</code> / <code>forced_off</code>)</li><li>Remoção de atribuições, que propaga a eliminação de substituições</li></ul><p>Aplica um teto de privilégio: um ator que não seja <code>super_admin</code> não pode modificar as suas próprias atribuições, nem pode conceder uma permissão que ele próprio não detenha. Ver <a href="/clearance-docs/pt/features/super-admin.html">Super Admin</a> e <a href="/clearance-docs/pt/features/users.html">Utilizadores</a>.</p><h2 id="excecoes" tabindex="-1">Exceções <a class="header-anchor" href="#excecoes" aria-label="Permalink to &quot;Exceções&quot;">​</a></h2><p>Todas em <code>src/Exceptions/</code>:</p><table tabindex="0"><thead><tr><th>Exceção</th><th>Lançada quando</th></tr></thead><tbody><tr><td><code>ClearanceConfigException</code></td><td>É lido um valor inválido ou mal configurado de <code>config/clearance.php</code> (ex. um <code>naming_separator</code> inválido).</td></tr><tr><td><code>ClearanceNamingException</code></td><td>Um nome de permissão viola a convenção de nomenclatura <code>group-action</code> enquanto a imposição está ativa.</td></tr><tr><td><code>ClearanceProtectedResourceException</code></td><td>É feita uma tentativa de modificar uma permissão <code>clearance-*</code> protegida, ou um recurso bloqueado, fora do fluxo de instalação.</td></tr><tr><td><code>ClearanceScopeViolationException</code></td><td>Uma relação de papel-teto inválida (um principal a tentar tornar-se filho, ou vice-versa), ou uma incompatibilidade de escopo.</td></tr></tbody></table><h2 id="ver-tambem" tabindex="-1">Ver também <a class="header-anchor" href="#ver-tambem" aria-label="Permalink to &quot;Ver também&quot;">​</a></h2><ul><li><a href="/clearance-docs/pt/api/facade.html">Facade</a> — o wrapper de chamada estática em torno do <code>ContextService</code>.</li><li><a href="/clearance-docs/pt/api/traits-directives.html">Traits &amp; Diretivas</a> — equivalentes de método de instância e diretiva Blade.</li><li><a href="/clearance-docs/pt/api/artisan-commands.html">Comandos Artisan</a> — <code>clearance:install</code> e <code>clearance:backfill</code>, que semeiam os dados sobre os quais estes serviços operam.</li></ul>',32)])])}const u=a(r,[["render",t]]);export{k as __pageData,u as default};
